#include "joystick.h"
#include <Arduino.h>
#include <math.h>
#define JOY_X 34
#define JOY_Y 35
#define JOY_SW 32
static int _x=0,_y=0;static bool _btn=false;static float _angle=0;static unsigned long _l=0;
void joystick_setup(){pinMode(JOY_X,INPUT);pinMode(JOY_Y,INPUT);pinMode(JOY_SW,INPUT_PULLUP);Serial.println("[joy] OK");}
void joystick_loop(){if(millis()-_l<50)return;_l=millis();_x=analogRead(JOY_X)-2048;_y=analogRead(JOY_Y)-2048;_btn=!digitalRead(JOY_SW);_angle=atan2((float)_y,(float)_x)*180.0/M_PI;}
int joystick_get_x(){return _x;}
int joystick_get_y(){return _y;}
bool joystick_button(){return _btn;}
float joystick_get_angle(){return _angle;}
